external_knowledge:
- "quite popular" refers to courses with higher than average total enrollment, specifically more than 1.5 times the overall average;
- "well-regarded" implies an overall rating of at least 4.0;
- "more students than usual" indicates a higher total enrollment;
- "more credits than the typical courses in their department" means a credit count greater than the average credit count for courses in the same department.

sql:
SELECT *
FROM course_evaluations
WHERE overall_rating > (SELECT AVG(overall_rating) FROM course_evaluations);

external_knowledge:
- "Shining star" metaphorically refers to the course with the highest rating;
- "Collected the highest average accolades" means that the course has the highest average rating;
- "Attracted a crowd of more than ten eager learners" indicates that the course has more than 10 students enrolled.

sql:
SELECT w.reason
FROM course_recommendations cr
JOIN withdrawals w ON cr.recommended_course_id = w.course_id;

SELECT SUM(count) 
FROM withdrawals 
WHERE reason = 'Academic';
